        onClose={() => setIsCustomizing(false)} 
        currentConfig={quickAccess}
        onSave={handleSaveConfig}
      />
    </div>
  )
}

"use client"

import { useState, useEffect } from "react"
import { supabase } from "@/lib/supabase"
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card"
import { Badge } from "@/components/ui/badge"
import { AlertTriangle, CheckCircle2, Truck, Clock, User, Settings, Info, Navigation2 } from "lucide-react"
import { cn } from "@/lib/utils"

export default function AdminFlotaPage() {
  const [vehiculos, setVehiculos] = useState<any[]>([])
  const [isLoading, setIsLoading] = useState(true)

  useEffect(() => {
    fetchVehiculos()

    // Set up real-time subscription for vehicle status changes
    const channel = supabase
      .channel('public:vehiculos_flota')
      .on('postgres_changes', { event: '*', schema: 'public', table: 'vehiculos' }, () => {
        fetchVehiculos()
      })
      .on('postgres_changes', { event: '*', schema: 'public', table: 'servicios_asignados' }, () => {
        fetchVehiculos()
      })
      .subscribe()

    return () => {
      supabase.removeChannel(channel)
    }
  }, [])

  const fetchVehiculos = async () => {
    try {
      const today = new Date().toISOString().split('T')[0]

      // Fetch all vehicles
      const { data: vehiculosData, error: vError } = await supabase
        .from('vehiculos')
        .select('*')
        .order('patente')

      if (vError) throw vError

      // Fetch today's services to see who is driving
      const { data: serviciosData, error: sError } = await supabase
        .from('servicios_asignados')
        .select(`
          id,
          vehiculo_id,
          usuarios:chofer_id (nombre),
          estado,
          fecha
        `)
        .eq('fecha', today)

      if (sError) console.warn("Error fetching services for fleet sync:", sError)

      // Join data in JS to avoid inner join ambiguity errors
      const processed = vehiculosData.map((v: any) => {
        const activeService = serviciosData?.find((s: any) => s.vehiculo_id === v.id && s.estado !== 'completado')
        const choferData = activeService?.usuarios as any
        const choferNombre = Array.isArray(choferData) 
          ? (choferData[0]?.nombre || 'Sin chofer asignado')
          : (choferData?.nombre || 'Sin chofer asignado')

        return {
          ...v,
          chofer_nombre: choferNombre,
          en_servicio: activeService ? true : false,
          estado: v.estado || 'OPERATIVO'
        }
      })

      setVehiculos(processed)
    } catch (error) {
      console.error("Error fetching fleet status:", error)
    } finally {
      setIsLoading(false)
    }
  }

  const getTimeAgo = (dateStr: string) => {
    if (!dateStr) return null
    const date = new Date(dateStr)
    const now = new Date()
    const diffMs = now.getTime() - date.getTime()
    const diffMins = Math.floor(diffMs / 60000)

    if (diffMins < 1) return 'Hace instantes'
    if (diffMins < 60) return `Hace ${diffMins} min`
    const diffHours = Math.floor(diffMins / 60)
    return `Hace ${diffHours} h`
  }

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-6">
        <div className="space-y-1">
          <h2 className="text-3xl font-black tracking-tight text-[#323232]">Monitoreo de Flota</h2>
          <p className="text-muted-foreground font-medium text-lg">Estatus y disponibilidad de activos en tiempo real.</p>
        </div>

        <div className="flex gap-4 p-4 bg-white/50 backdrop-blur-sm rounded-2xl shadow-sm border border-muted/50 font-black text-[10px] tracking-widest uppercase">
          <div className="flex items-center gap-2 px-3 py-1.5 rounded-lg bg-emerald-50 text-emerald-700">
            <div className="size-2 rounded-full bg-emerald-500" />
            <span>Operativos: {vehiculos.filter(v => !v.estado || v.estado === 'OPERATIVO').length}</span>
          </div>
          <div className="flex items-center gap-2 px-3 py-1.5 rounded-lg bg-destructive/10 text-destructive">
            <div className="size-2 rounded-full bg-destructive" />
            <span>Fallas: {vehiculos.filter(v => v.estado && v.estado !== 'OPERATIVO').length}</span>
          </div>
        </div>
      </div>

      {isLoading ? (
        <div className="grid gap-6 md:grid-cols-2 lg:grid-cols-3">
          {[1,2,3,4,5,6].map(i => <div key={i} className="h-60 bg-muted animate-pulse rounded-[2rem]" />)}
        </div>
      ) : (
        <div className="grid gap-6 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4">
          {vehiculos.map((v) => {
            const isFaulty = v.estado && v.estado !== 'OPERATIVO'

            return (
              <Card key={v.id} className={cn(
                "transition-all duration-300 shadow-sm border-none ring-1 ring-black/5 rounded-[2rem] overflow-hidden group",
                isFaulty ? "bg-red-50/10" : "bg-white"
              )}>
                <CardHeader className={cn(
                    "flex flex-row items-center justify-between p-6 pb-4",
                    isFaulty ? "bg-destructive text-white" : "bg-[#f8fcf8]"
                )}>
                  <div className="space-y-1">
                    <CardTitle className="text-xl font-black flex items-center gap-2 tracking-tight">
                      <Truck className={cn("size-6", isFaulty ? "text-white" : "text-[#51872E]")} />
                      {v.patente}
                    </CardTitle>
                    <CardDescription className={cn(
                        "font-bold uppercase text-[9px] tracking-widest",
                        isFaulty ? "text-red-100" : "text-muted-foreground"
                    )}>
                      {v.tipo}
                    </CardDescription>
                  </div>
                  {isFaulty ? (
                    <div className="bg-white/20 p-2 rounded-full">
                       <AlertTriangle className="size-6 text-white animate-pulse" />
                    </div>
                  ) : (
                    <div className="bg-emerald-500/10 p-2 rounded-full">
                       <CheckCircle2 className="size-6 text-[#51872E]" />
                    </div>
                  )}
                </CardHeader>

                <CardContent className="p-6 space-y-4">
                  <div className="flex justify-between items-center bg-zinc-50 border rounded-xl p-3 border-muted/50">
                     <div className="flex items-center gap-2">
                        <User className="size-4 text-muted-foreground" />
                        <span className="text-xs font-bold text-[#323232] truncate max-w-[120px]">
                           {v.chofer_nombre || 'Sin Chofer'}
                        </span>
                     </div>
                     <Badge variant="outline" className={cn(
                        "text-[9px] font-black uppercase tracking-tighter px-1.5 py-0",
                        v.en_servicio ? "border-blue-200 text-blue-600 bg-blue-50" : "border-zinc-200 text-zinc-400"
                     )}>
                        {v.en_servicio ? 'En Ruta' : 'Disponible'}
                     </Badge>
                  </div>


                  <div className="space-y-2 px-1">
                    <p className={cn(
                        "text-[10px] font-black uppercase tracking-[0.2em]",
                        isFaulty ? "text-destructive" : "text-[#51872E]"
                    )}>
                        Estatus: {v.estado}
                    </p>

                    <div className="bg-muted/30 p-4 rounded-2xl border border-muted/20 min-h-[70px] relative overflow-hidden group-hover:bg-white transition-colors">
                      <p className="text-xs text-[#323232] font-semibold leading-relaxed line-clamp-2 italic relative z-10">
                        "{v.ultima_falla || (v.estado === 'OPERATIVO' ? "Operación estable." : "Sin reporte detallado.")}"
                      </p>
                      <Info className="absolute -bottom-1 -right-1 size-8 opacity-5 text-muted-foreground group-hover:opacity-10" />
                    </div>
                  </div>

                  {v.reporte_falla_at && (
                    <div className="flex items-center gap-1.5 text-[10px] text-muted-foreground font-black uppercase tracking-widest pt-2 px-1">
                      <Clock className="size-3" />
                      {getTimeAgo(v.reporte_falla_at)}
                    </div>
                  )}
                </CardContent>
              </Card>
            )
          })}
        </div>
      )}

      <div className="p-8 bg-[#116CA2]/5 rounded-[2rem] flex items-center gap-6 border border-[#116CA2]/10 backdrop-blur-sm">
         <div className="bg-[#116CA2] p-4 rounded-2xl shadow-lg">
            <Settings className="size-10 text-white animate-[spin_8s_linear_infinite]" />
         </div>
         <div className="flex-1">
            <h3 className="text-xl font-black text-[#116CA2] tracking-tight">Sincronización GPS & Mantenimiento</h3>
            <p className="text-sm font-medium text-muted-foreground max-w-2xl">
               Los estados se actualizan automáticamente cada vez que un conductor reporta una novedad desde su consola móvil. 
               El botón de "Reportar Falla" genera una alerta inmediata en este tablero.
            </p>
         </div>
      </div>
    </div>
  )
}

"use client"

import { useState, useEffect } from "react"
import { supabase } from "@/lib/supabase"
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select"
import { Badge } from "@/components/ui/badge"
import { Plus, List, Calendar as CalendarIcon, Truck, User, MapPin, Package, Clock, CheckCircle2, XCircle } from "lucide-react"
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription, DialogFooter } from "@/components/ui/dialog"
import CalendarComponent from "@/components/CalendarComponent"
import { NavigationHeader } from "@/components/NavigationHeader"
import { cn } from "@/lib/utils"
import { useOfflineSync } from "@/hooks/useOfflineSync"

export default function AdminPage() {
  const { isOnline, addToOfflineQueue } = useOfflineSync()
  const [activeTab, setActiveTab] = useState("calendar")
  const [servicios, setServicios] = useState<any[]>([])
  const [usuarios, setUsuarios] = useState<any[]>([])
  const [vehiculos, setVehiculos] = useState<any[]>([])
  const [clientes, setClientes] = useState<any[]>([])
  const [isLoading, setIsLoading] = useState(true)
  const [anularTarget, setAnularTarget] = useState<any>(null)
  const [isAnulando, setIsAnulando] = useState(false)

  // Form states
  const [origen, setOrigen] = useState("")
  const [destino, setDestino] = useState("")
  const [carga, setCarga] = useState("")
  const [categoriaResiduo, setCategoriaResiduo] = useState("")
  const [tipoContenedor, setTipoContenedor] = useState("")
  const [choferId, setChoferId] = useState("")
  const [vehiculoId, setVehiculoId] = useState("")
  const [fechaPlanificacion, setFechaPlanificacion] = useState(new Date().toISOString().split('T')[0])
  const [bonoTipoVehiculo, setBonoTipoVehiculo] = useState<string>("CAMION")

  useEffect(() => {
    fetchData()

    // Real-time synchronization
    const channel = supabase
      .channel('public:servicios_planificacion')
      .on('postgres_changes', { event: '*', schema: 'public', table: 'servicios_asignados' }, () => {
        fetchData()
      })
      .on('postgres_changes', { event: '*', schema: 'public', table: 'vehiculos' }, () => {
        fetchData()
      })
      .on('postgres_changes', { event: '*', schema: 'public', table: 'usuarios', filter: "rol=eq.chofer" }, () => {
        fetchData()
      })
      .subscribe()

    return () => {
      supabase.removeChannel(channel)
    }
  }, [])

  const fetchData = async () => {
    setIsLoading(true)
    try {
      const resServs = await fetch('/api/proxy', {
        method: 'POST',
        body: JSON.stringify({
          table: 'servicios_asignados',
          method: 'select',
          data: `
            *,
            usuarios:chofer_id (id, nombre),
            vehiculos:vehiculo_id (id, patente, tipo)
          `
        })
      })
      const { data: servs } = await resServs.json()

      const resUsrs = await fetch('/api/proxy', {
        method: 'POST',
        body: JSON.stringify({
          table: 'usuarios',
          method: 'select',
          match: { rol: 'chofer' }
        })
      })
      const { data: usrs } = await resUsrs.json()

      const resVehs = await fetch('/api/proxy', {
        method: 'POST',
        body: JSON.stringify({
          table: 'vehiculos',
          method: 'select'
        })
      })
      const { data: vehs } = await resVehs.json()

      const resClis = await fetch('/api/proxy', {
        method: 'POST',
        body: JSON.stringify({
          table: 'clientes',
          method: 'select'
        })
      })
      const { data: clis } = await resClis.json()

      if (servs) setServicios(servs)
      if (usrs) setUsuarios(usrs)
      if (vehs) setVehiculos(vehs)
      if (clis) setClientes(clis)
    } catch (err) {
      console.error("Error fetching data:", err)
    } finally {
      setIsLoading(false)
    }
  }

  const handleAddServicio = async (e: React.FormEvent) => {
    e.preventDefault()
    if (!choferId || !vehiculoId || !origen || !destino) return

    const servicioData = {
      chofer_id: choferId,
      vehiculo_id: vehiculoId,
      origen,
      destino,
      carga: categoriaResiduo ? `${categoriaResiduo} - ${tipoContenedor}` : carga,
      tipo_servicio: "RETIRO", // Hardcoded default to satisfy DB without changing UI
      fecha: fechaPlanificacion,
      estado: 'pendiente',
      bono_tipo_vehiculo: bonoTipoVehiculo
    }

    try {
      if (!isOnline) {
        addToOfflineQueue('servicios_asignados', servicioData)
        alert("Sin conexión. La asignación se ha guardado localmente y se sincronizará automáticamente al recuperar internet.")
      } else {
        const res = await fetch('/api/proxy', {
          method: 'POST',
          body: JSON.stringify({
            table: 'servicios_asignados',
            method: 'insert',
            data: [servicioData]
          })
        })
        if (!res.ok) {
           const errBody = await res.json()
           throw new Error(errBody.error || "Error al guardar en base de datos")
        }
      }

      // Reset form
      setOrigen("")
      setDestino("")
      setCarga("")
      setCategoriaResiduo("")
      setTipoContenedor("")
      setChoferId("")
      setVehiculoId("")
      setBonoTipoVehiculo("CAMION")

      if (isOnline) fetchData()
    } catch (err: any) {
      console.error("Error adding service:", err)
      // Fallback to offline queue if request fails
      addToOfflineQueue('servicios_asignados', servicioData)
      alert(`Error: ${err.message || "Error de conexión"}. Se guardó localmente.`)
    }
  }

  const handleAnularViaje = async () => {
    if (!anularTarget) return
    setIsAnulando(true)
    try {
      const res = await fetch('/api/proxy', {
        method: 'POST',
        body: JSON.stringify({
          table: 'servicios_asignados',
          method: 'update',
          data: { estado: 'anulado' },
          match: { id: anularTarget.id }
        })
      })
      const { error } = await res.json()
      if (error) throw new Error(error)
      setAnularTarget(null)
      fetchData()
    } catch (err: any) {
      console.error("Error anulando viaje:", err)
      alert(`Error al anular: ${err.message || "Intente nuevamente"}`)
    } finally {
      setIsAnulando(false)
    }
  }

  return (
    <div className="min-h-screen bg-[#FFF9F0] dark:bg-zinc-950">
      <NavigationHeader title="Planificación Operativa" subtitle="Centro de Control Tresol" />

      <main className="p-8 md:p-10 max-w-7xl mx-auto">
        <div className="space-y-8 animate-in fade-in duration-500">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-6">
        <div className="space-y-1">
          <h2 className="text-3xl font-black tracking-tight text-[#323232]">Planificación Operativa</h2>
          <p className="text-muted-foreground font-medium text-lg">Centro de Control y Despacho Tresol</p>
        </div>

        <div className="flex bg-white/50 backdrop-blur-sm p-1.5 rounded-2xl shadow-inner border border-muted dark:bg-zinc-900/50">
          <button
            onClick={() => setActiveTab("calendar")}
            className={cn(
              "flex items-center gap-2 px-6 py-2.5 rounded-xl font-bold transition-all text-sm uppercase tracking-widest",
              activeTab === "calendar" 
                ? "bg-[#51872E] text-white shadow-lg shadow-[#51872E]/20" 
                : "text-muted-foreground hover:text-foreground"
            )}
          >
            <CalendarIcon className="size-4" />
            Calendario
          </button>
          <button
            onClick={() => setActiveTab("list")}
            className={cn(
              "flex items-center gap-2 px-6 py-2.5 rounded-xl font-bold transition-all text-sm uppercase tracking-widest",
              activeTab === "list" 
                ? "bg-[#51872E] text-white shadow-lg shadow-[#51872E]/20" 
                : "text-muted-foreground hover:text-foreground"
            )}
          >
            <List className="size-4" />
            Hoy
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 items-start">
        {/* Sidebar Form: Nueva Asignación */}
        <div className="lg:col-span-4 space-y-6">
          <Card className="shadow-2xl border-none ring-1 ring-black/5 rounded-[2rem] overflow-hidden bg-white/90 backdrop-blur-md">
            <CardHeader className="bg-[#116CA2] text-white p-8">
              <div className="flex items-center gap-3 mb-2">
                 <Plus className="size-6" />
                 <CardTitle className="text-2xl font-black tracking-tight">Nueva Asignación</CardTitle>
              </div>
              <CardDescription className="text-blue-100 font-medium opacity-90">Programación de servicios y rutas.</CardDescription>
            </CardHeader>
            <CardContent className="p-8 space-y-5">
              <form onSubmit={handleAddServicio} className="space-y-5">
                <div className="space-y-2">
                  <Label className="text-[10px] font-black uppercase tracking-widest text-muted-foreground ml-1">Fecha Programada</Label>
                  <Input 
                    type="date" 
                    value={fechaPlanificacion} 
                    onChange={(e) => setFechaPlanificacion(e.target.value)} 
                    className="h-12 rounded-xl border-muted bg-zinc-50 focus:ring-2 focus:ring-[#116CA2]/20 font-bold"
                  />
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-1 gap-4">
                  <div className="space-y-2">
                    <Label className="text-[10px] font-black uppercase tracking-widest text-muted-foreground ml-1">Conductor Responsable</Label>
                    <Select value={choferId} onValueChange={(v) => setChoferId(v || "")}>
                      <SelectTrigger className="h-12 rounded-xl border-muted bg-zinc-50 font-bold">
                        <SelectValue placeholder="Seleccionar...">
                           {usuarios.find(u => u.id === choferId)?.nombre}
                        </SelectValue>
                      </SelectTrigger>
                      <SelectContent className="rounded-xl border-muted shadow-xl">
                        {usuarios.map((u) => (
                          <SelectItem key={u.id} value={u.id} className="py-3 font-semibold">{u.nombre}</SelectItem>
                        ))}
                      </SelectContent>
                    </Select>
                  </div>

                  <div className="space-y-2">
                    <Label className="text-[10px] font-black uppercase tracking-widest text-muted-foreground ml-1">Vehículo Asignado</Label>
                    <Select value={vehiculoId} onValueChange={(v) => setVehiculoId(v || "")}>
                      <SelectTrigger className="h-12 rounded-xl border-muted bg-zinc-50 font-bold">
                        <SelectValue placeholder="Seleccionar...">
                           {vehiculos.find(v => v.id === vehiculoId)?.patente}
                        </SelectValue>
                      </SelectTrigger>
                      <SelectContent className="rounded-xl border-muted shadow-xl">
                        {vehiculos.map((v) => (
                          <SelectItem key={v.id} value={v.id} className="py-3 font-semibold">
                            {v.patente} ({v.tipo})
                          </SelectItem>
                        ))}
                      </SelectContent>
                    </Select>
                  </div>
                </div>

                <div className="space-y-2">
                  <Label className="text-[10px] font-black uppercase tracking-widest text-muted-foreground ml-1">Tipo para Bono</Label>
                  <div className="grid grid-cols-2 gap-2 bg-zinc-100 p-1 rounded-xl border border-muted">
                     <button 
                        type="button"
                        onClick={() => setBonoTipoVehiculo("CAMION")}
                        className={cn(
                           "py-2 px-3 text-[10px] font-black uppercase rounded-lg transition-all",
                           bonoTipoVehiculo === "CAMION" ? "bg-white shadow text-[#116CA2] shadow-sm" : "text-muted-foreground hover:bg-white/50"
                        )}
                     >
                        C. Simple
                     </button>
                     <button 
                        type="button"
                        onClick={() => setBonoTipoVehiculo("CAMION+CARRO")}
                        className={cn(
                           "py-2 px-3 text-[10px] font-black uppercase rounded-lg transition-all",
                           bonoTipoVehiculo === "CAMION+CARRO" ? "bg-white shadow text-[#116CA2] shadow-sm" : "text-muted-foreground hover:bg-white/50"
                        )}
                     >
                        C. + Carro
                     </button>
                  </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-1 gap-4">
                  <div className="space-y-2">
                    <Label className="text-[10px] font-black uppercase tracking-widest text-muted-foreground ml-1">Ruta Origen</Label>
                    <Select value={origen} onValueChange={(v) => {
                      setOrigen(v || "")
                      setDestino("") // Reset destination when origin changes
                    }}>
                      <SelectTrigger className="h-12 rounded-xl border-muted bg-zinc-50 font-bold">
                        <SelectValue placeholder="Seleccionar Origen..." />
                      </SelectTrigger>
                      <SelectContent className="rounded-xl border-muted shadow-xl">
                        {Array.from(new Set(clientes.map(c => c.nombre))).map((nombre) => (
                          <SelectItem key={nombre} value={nombre} className="py-3 font-semibold">{nombre}</SelectItem>
                        ))}
                      </SelectContent>
                    </Select>
                  </div>

                  <div className="space-y-2">
                    <Label className="text-[10px] font-black uppercase tracking-widest text-muted-foreground ml-1">Ruta Destino</Label>
                    <Select 
                      key={origen} // Force re-mount when origin changes
                      value={destino} 
                      onValueChange={(v) => setDestino(v || "")}
                    >
                      <SelectTrigger 
                        disabled={!origen}
                        className="h-12 rounded-xl border-muted bg-zinc-50 font-bold"
                      >
                        <SelectValue placeholder={origen ? "Seleccionar Destino..." : "Seleccione Origen Primero"} />
                      </SelectTrigger>
                      <SelectContent className="rounded-xl border-muted shadow-xl">
                        {clientes
                          .filter(c => c.nombre === origen)
                          .map((c, idx) => (
                            <SelectItem key={`${c.disposicion_final}-${idx}`} value={c.disposicion_final} className="py-3 font-semibold">
                              {c.disposicion_final}
                            </SelectItem>
                          ))
                        }
                      </SelectContent>
                    </Select>
                  </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-1 gap-4 mt-2">
                  <div className="space-y-2">
                    <Label className="text-[10px] font-black uppercase tracking-widest text-muted-foreground ml-1">Categoría RISES</Label>
                    <Select value={categoriaResiduo} onValueChange={(v) => setCategoriaResiduo(v || "")}>
                      <SelectTrigger className="h-12 rounded-xl border-muted bg-zinc-50 font-bold">
                        <SelectValue placeholder="Tipo de Residuo..." />
                      </SelectTrigger>
                      <SelectContent className="rounded-xl border-muted shadow-xl">
                        <SelectItem value="Asimilables" className="py-3 font-semibold">Asimilables</SelectItem>
                        <SelectItem value="Lodos" className="py-3 font-semibold">Lodos</SelectItem>
                        <SelectItem value="Escombros" className="py-3 font-semibold">Escombros</SelectItem>
                        <SelectItem value="Residuos Peligrosos" className="py-3 font-semibold">Residuos Peligrosos</SelectItem>
                        <SelectItem value="Residuos Industriales" className="py-3 font-semibold">Residuos Industriales</SelectItem>
                        <SelectItem value="Residuos Valorizables" className="py-3 font-semibold">Residuos Valorizables</SelectItem>
                      </SelectContent>
                    </Select>
                  </div>

                  <div className="space-y-2">
                    <Label className="text-[10px] font-black uppercase tracking-widest text-muted-foreground ml-1">Tipo Contenedor</Label>
                    <Select value={tipoContenedor} onValueChange={(v) => setTipoContenedor(v || "")}>
                      <SelectTrigger className="h-12 rounded-xl border-muted bg-zinc-50 font-bold">
                        <SelectValue placeholder="Seleccionar Contenedor..." />
                      </SelectTrigger>
                      <SelectContent className="rounded-xl border-muted shadow-xl">
                        <SelectItem value="Compactador Estacionario" className="py-3 font-semibold">Compactador Estacionario</SelectItem>
                        <SelectItem value="Contenedor cerrado" className="py-3 font-semibold">Contenedor cerrado</SelectItem>
                        <SelectItem value="Contenedor abierto" className="py-3 font-semibold">Contenedor abierto</SelectItem>
                        <SelectItem value="Estanque algibe o lodo" className="py-3 font-semibold">Estanque algibe o lodo</SelectItem>
                      </SelectContent>
                    </Select>
                  </div>
                </div>

                <div className="space-y-2">
                  <Label className="text-[10px] font-black uppercase tracking-widest text-muted-foreground ml-1">Notas Adicionales</Label>
                  <Input 
                    placeholder="Ej: Lodos, Industriales, etc." 
                    value={carga} 
                    onChange={(e) => setCarga(e.target.value)} 
                    className="h-12 rounded-xl border-muted bg-zinc-50 font-bold"
                  />
                </div>

                <Button type="submit" className="w-full h-14 rounded-2xl bg-[#51872E] hover:bg-[#406B24] text-white font-black shadow-lg shadow-[#51872E]/20 transition-all active:scale-[0.98] mt-4">
                   CONFIRMAR ASIGNACIÓN
                </Button>
              </form>
            </CardContent>
          </Card>
        </div>

        {/* Main Area: Calendar or List */}
        <div className="lg:col-span-8">
          {activeTab === "calendar" ? (
            <Card className="shadow-2xl border-none ring-1 ring-black/5 rounded-[2rem] overflow-hidden bg-white/90 backdrop-blur-md h-full">
              <CalendarComponent services={servicios} />
            </Card>
          ) : (
            <div className="space-y-4 h-full">
              {isLoading ? (
                Array(3).fill(0).map((_, i) => (
                  <div key={i} className="h-32 bg-muted animate-pulse rounded-[2rem]" />
                ))
              ) : servicios.filter(s => s.fecha === new Date().toISOString().split('T')[0]).length === 0 ? (
                <Card className="h-full flex flex-col items-center justify-center p-12 border-dashed border-2 rounded-[2rem] bg-zinc-50/50">
                   <Clock className="size-16 text-muted mb-4 opacity-20" />
                   <h3 className="text-xl font-black text-muted-foreground">Sin servicios para hoy</h3>
                   <p className="text-sm text-muted-foreground font-medium text-center max-w-xs mt-2">La lista está vacía. Comience programando una ruta desde el panel lateral.</p>
                </Card>
              ) : (
                servicios
                  .filter(s => s.fecha === new Date().toISOString().split('T')[0])
                  .map((s) => (
                    <Card key={s.id} className="shadow-sm hover:shadow-xl transition-all border-none ring-1 ring-black/5 rounded-[2rem] bg-white group overflow-hidden">
                      <div className="flex flex-col md:flex-row divide-y md:divide-y-0 md:divide-x divide-muted/30">
                        <div className="p-8 md:w-2/3 space-y-4">
                           <div className="flex items-center gap-3">
                              <Badge className={cn(
                                "rounded-full px-3 py-1 font-black text-[10px] tracking-widest uppercase",
                                s.estado === 'pendiente' ? "bg-amber-100 text-amber-700" :
                                s.estado === 'completado' ? "bg-emerald-100 text-emerald-700" :
                                s.estado === 'anulado' ? "bg-red-100 text-red-700" :
                                "bg-blue-100 text-blue-700"
                              )}>
                                {s.estado}
                              </Badge>
                              <span className="text-[10px] font-bold text-muted-foreground uppercase tracking-widest flex items-center gap-1.5">
                                <Clock className="size-3" />
                                {new Date(s.created_at).toLocaleTimeString('es-CL', { hour: '2-digit', minute: '2-digit' })}
                              </span>
                           </div>

                           <div className="flex items-center gap-8">
                             <div className="space-y-1">
                                <p className="text-[9px] font-black uppercase text-muted-foreground">Ruta</p>
                                <div className="flex items-center gap-3 font-bold text-[#323232]">
                                   <span>{s.origen}</span>
                                   <div className="h-px w-8 bg-muted" />
                                   <span className="text-[#116CA2]">{s.destino}</span>
                                </div>
                             </div>
                             <div className="space-y-1">
                                <p className="text-[9px] font-black uppercase text-muted-foreground">Carga</p>
                                <p className="font-bold text-[#323232]">{s.carga || 'General'}</p>
                             </div>
                           </div>
                        </div>

                        <div className="p-8 md:w-1/3 bg-zinc-50/50 flex flex-col justify-center space-y-3">
                           <div className="flex items-center gap-3">
                              <div className="bg-white p-2 rounded-lg shadow-sm">
                                 <User className="size-4 text-[#51872E]" />
                              </div>
                              <div className="min-w-0">
                                 <p className="text-[8px] font-black uppercase text-muted-foreground leading-none mb-1">Conductor</p>
                                 <p className="font-bold text-sm truncate">{s.usuarios?.nombre || 'TBD'}</p>
                              </div>
                           </div>
                           <div className="flex items-center gap-3">
                              <div className="bg-white p-2 rounded-lg shadow-sm">
                                 <Truck className="size-4 text-[#116CA2]" />
                              </div>
                              <div className="min-w-0">
                                 <p className="text-[8px] font-black uppercase text-muted-foreground leading-none mb-1">Vehículo</p>
                                 <p className="font-bold text-sm truncate uppercase">{s.vehiculos?.patente || 'TBD'} <span className="text-[10px] text-muted-foreground ml-1">({s.vehiculos?.tipo})</span></p>
                              </div>
                           </div>
                        </div>

                        <div className="p-4 flex flex-col items-center justify-center bg-white group-hover:bg-red-50/30 transition-colors min-w-[80px]">
                           {s.estado !== 'anulado' && s.estado !== 'completado' ? (
                             <Button
                               variant="ghost"
                               size="sm"
                               onClick={() => setAnularTarget(s)}
                               className="rounded-xl text-red-500 hover:text-red-700 hover:bg-red-50 font-black text-xs uppercase tracking-wider h-auto px-3 py-2 gap-1.5"
                             >
                               <XCircle className="size-4" />
                               Anular
                             </Button>
                           ) : (
                             <div className={cn(
                               "text-[10px] font-black uppercase tracking-widest px-2 py-1.5 rounded-lg text-center",
                               s.estado === 'completado' ? "text-emerald-500 bg-emerald-50" : "text-red-400 bg-red-50"
                             )}>
                               {s.estado === 'completado' ? 'Completado' : 'Anulado'}
                             </div>
                           )}
                        </div>
                      </div>
                    </Card>
                  ))
              )}
            </div>
          )}
        </div>
      </div>

      {/* ---- Anular Confirmation Dialog ---- */}
      <Dialog open={!!anularTarget} onOpenChange={(open) => { if (!open) setAnularTarget(null) }}>
        <DialogContent className="sm:max-w-md rounded-[2rem] border-none shadow-2xl p-0 overflow-hidden">
          <div className="bg-red-600 p-8 flex flex-col items-center gap-3 text-white text-center">
            <div className="bg-white/20 p-3 rounded-full">
              <XCircle className="size-8" />
            </div>
            <DialogTitle className="text-2xl font-black uppercase tracking-tight">Anular Viaje</DialogTitle>
            <DialogDescription className="text-red-100 font-medium">
              Esta acción es irreversible. El viaje quedará marcado como anulado.
            </DialogDescription>
          </div>
          <div className="p-8 space-y-4">
            {anularTarget && (
              <div className="bg-red-50 rounded-2xl p-4 space-y-1 text-sm">
                <p className="font-black text-red-800 uppercase text-xs tracking-wider">Servicio a anular</p>
                <p className="font-bold text-[#323232]">{anularTarget.origen} → {anularTarget.destino}</p>
                <p className="text-muted-foreground font-medium">Conductor: {anularTarget.usuarios?.nombre || 'Sin asignar'}</p>
              </div>
            )}
            <DialogFooter className="flex gap-3 sm:flex-row">
              <Button variant="outline" className="flex-1 h-12 rounded-xl font-bold" onClick={() => setAnularTarget(null)}>
                CANCELAR
              </Button>
              <Button
                variant="destructive"
                className="flex-1 h-12 rounded-xl font-black shadow-lg shadow-red-500/20"
                onClick={handleAnularViaje}
                disabled={isAnulando}
              >
                {isAnulando ? 'ANULANDO...' : 'CONFIRMAR ANULACIÓN'}
              </Button>
            </DialogFooter>
          </div>
        </DialogContent>
      </Dialog>
        </div>
      </main>
    </div>
  )
}

"use client"

import React, { useState, useEffect } from "react"
import { 
  Shield, 
  Search, 
  LogIn, 
  LogOut, 
  UserPlus, 
  Building2, 
  Truck, 
  History,
  Clock,
  ArrowRight,
  Loader2,
  ChevronRight,
  Calendar,
  MapPin
} from "lucide-react"
import { Button } from "@/components/ui/button"
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card"
import { Input } from "@/components/ui/input"
import { Badge } from "@/components/ui/badge"
import { NavigationHeader } from "@/components/NavigationHeader"
import { cn } from "@/lib/utils"

export default function PorteriaPage() {
  const [activePorteria, setActivePorteria] = useState<'husamontt' | 'tresol_antiguo'>('husamontt')
  const [searchTerm, setSearchTerm] = useState("")
  const [maestro, setMaestro] = useState<any[]>([])
  const [logs, setLogs] = useState<any[]>([])
  const [isLoading, setIsLoading] = useState(true)
  const [isProcessing, setIsProcessing] = useState<string | null>(null)

  // Registration modal state for externals (simplified as inline form for now)
  const [showExternalForm, setShowExternalForm] = useState(false)
  const [externalData, setExternalData] = useState({
    nombre: '',
    empresa: '',
    patente: '',
    observacion: ''
  })

  useEffect(() => {
    fetchData()
  }, [])

  const fetchData = async () => {
    setIsLoading(true)
    try {
      const [maestroRes, logsRes] = await Promise.all([
        fetch('/api/proxy', {
          method: 'POST',
          body: JSON.stringify({ table: 'maestro_personas', method: 'select' })
        }),
        fetch('/api/proxy', {
          method: 'POST',
          body: JSON.stringify({ 
            table: 'logs_porteria', 
            method: 'select',
            data: '*, persona:maestro_personas(nombre, apellido)'
          })
        })
      ])

      const maestroData = await maestroRes.json()
      const logsData = await logsRes.json()

      setMaestro(maestroData.data || [])
      setLogs(logsData.data || [])
    } catch (error) {
      console.error("Error fetching data:", error)
    } finally {
      setIsLoading(false)
    }
  }

  const handleRegisterEntry = async (persona: any) => {
    setIsProcessing(`entry-${persona.id}`)
    try {
      const res = await fetch('/api/proxy', {
        method: 'POST',
        body: JSON.stringify({
          table: 'logs_porteria',
          method: 'insert',
          data: {
            persona_id: persona.id,
            empresa: persona.empresa,
            patente: persona.patente_default,
            porteria: activePorteria,
            hora_ingreso: new Date().toISOString()
          }
        })
      })
      if (res.ok) {
        fetchData()
        setSearchTerm("")
      }
    } catch (error) {
      console.error("Error registering entry:", error)
    } finally {
      setIsProcessing(null)
    }
  }

  const handleRegisterExit = async (logId: string) => {
    setIsProcessing(`exit-${logId}`)
    try {
      const res = await fetch('/api/proxy', {
        method: 'POST',
        body: JSON.stringify({
          table: 'logs_porteria',
          method: 'update',
          match: { id: logId },
          data: {
            hora_salida: new Date().toISOString()
          }
        })
      })
      if (res.ok) fetchData()
    } catch (error) {
      console.error("Error registering exit:", error)
    } finally {
      setIsProcessing(null)
    }
  }

  const handleExternalSubmit = async (e: React.FormEvent) => {
    e.preventDefault()
    setIsProcessing('external')
    try {
      const res = await fetch('/api/proxy', {
        method: 'POST',
        body: JSON.stringify({
          table: 'logs_porteria',
          method: 'insert',
          data: {
            nombre_manual: externalData.nombre,
            empresa: externalData.empresa,
            patente: externalData.patente,
            observacion: externalData.observacion,
            porteria: activePorteria,
            hora_ingreso: new Date().toISOString()
          }
        })
      })
      if (res.ok) {
        setExternalData({ nombre: '', empresa: '', patente: '', observacion: '' })
        setShowExternalForm(false)
        fetchData()
      }
    } catch (error) {
      console.error("Error registering external:", error)
    } finally {
      setIsProcessing(null)
    }
  }

  const filteredMaestro = maestro.filter(p => 
    `${p.nombre} ${p.apellido}`.toLowerCase().includes(searchTerm.toLowerCase()) ||
    p.rut?.toLowerCase().includes(searchTerm.toLowerCase())
  ).slice(0, 6)

  const activeEntries = logs.filter(l => !l.hora_salida && l.porteria === activePorteria)
  const recentExits = logs.filter(l => l.hora_salida && l.porteria === activePorteria).slice(0, 5)

  return (
    <div className="min-h-screen bg-[#F8FAFC] dark:bg-zinc-950 font-sans selection:bg-[#51872E] selection:text-white">
      <NavigationHeader 
        title="Control Portería" 
        subtitle={activePorteria === 'husamontt' ? "Sede Husamontt" : "Sede Tresol Antiguo"}
      />

      {/* Porteria Selection (Now below header) */}
      <div className="fixed top-20 w-full z-40 bg-zinc-50/80 backdrop-blur-sm border-b border-slate-100 h-14 flex items-center justify-center px-10">
           <div className="flex items-center bg-slate-200/50 p-1 rounded-xl">
              <button 
                onClick={() => setActivePorteria('husamontt')}
                className={cn(
                  "px-6 py-1.5 rounded-lg text-[10px] font-black transition-all uppercase tracking-widest",
                  activePorteria === 'husamontt' ? "bg-white text-[#116CA2] shadow-sm" : "text-slate-500 hover:text-slate-700"
                )}
              >
                Husamontt
              </button>
              <button 
                onClick={() => setActivePorteria('tresol_antiguo')}
                className={cn(
                  "px-6 py-1.5 rounded-lg text-[10px] font-black transition-all uppercase tracking-widest",
                  activePorteria === 'tresol_antiguo' ? "bg-white text-[#116CA2] shadow-sm" : "text-slate-500 hover:text-slate-700"
                )}
              >
                Tresol Antiguo
              </button>
           </div>
      </div>

      <main className="pt-40 pb-20 px-10 max-w-7xl mx-auto">
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-10 items-start">

          {/* Left Column: Search & Quick Access */}
          <div className="lg:col-span-7 space-y-8">
            <Card className="border-none shadow-xl shadow-slate-200/50 rounded-[2.5rem] bg-white overflow-hidden">
               <CardContent className="p-10 space-y-8">
                  <div className="space-y-2">
                    <h2 className="text-2xl font-black text-[#323232]">Registrar Ingreso</h2>
                    <p className="text-sm text-slate-500 font-medium font-sans">Busca un trabajador o ingresa una visita externa.</p>
                  </div>

                  <div className="relative">
                    <Search className="absolute left-5 top-1/2 -translate-y-1/2 size-6 text-slate-400" />
                    <Input 
                      placeholder="Busca por Nombre, Apellido o RUT..."
                      className="h-16 pl-14 pr-6 bg-slate-50 border-none rounded-2xl text-lg font-bold placeholder:text-slate-300 focus-visible:ring-2 focus-visible:ring-[#116CA2]/50"
                      value={searchTerm}
                      onChange={(e) => setSearchTerm(e.target.value)}
                    />
                  </div>

                  {searchTerm.length > 0 && (
                    <div className="space-y-3 animate-in fade-in slide-in-from-top-4">
                       {filteredMaestro.map(person => (
                         <div key={person.id} className="flex items-center justify-between p-4 rounded-2xl bg-slate-50 border border-slate-100 hover:bg-white hover:shadow-lg transition-all group">
                            <div className="flex items-center gap-4">
                               <div className="size-12 rounded-xl bg-white flex items-center justify-center border border-slate-100 shadow-sm group-hover:bg-[#116CA2] group-hover:text-white transition-colors">
                                  <Truck className="size-6" />
                               </div>
                               <div>
                                  <p className="font-black text-[#323232]">{person.nombre} {person.apellido}</p>
                                  <div className="flex items-center gap-2">
                                     <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">{person.empresa}</span>
                                     <span className="text-slate-200">•</span>
                                     <span className="text-[10px] font-bold text-[#116CA2] uppercase tracking-widest">{person.patente_default || 'S/P'}</span>
                                  </div>
                               </div>
                            </div>
                            <Button 
                              className="bg-[#51872E] hover:bg-[#437126] text-white rounded-xl font-black px-6 h-10 shadow-lg shadow-[#51872E]/20"
                              onClick={() => handleRegisterEntry(person)}
                              disabled={!!isProcessing}
                            >
                               {isProcessing === `entry-${person.id}` ? <Loader2 className="animate-spin size-4" /> : 'INGRESAR'}
                            </Button>
                         </div>
                       ))}
                    </div>
                  )}

                  <div className="pt-4 border-t border-slate-100 flex items-center justify-between">
                     <p className="text-xs font-bold text-slate-400 italic">¿Nuevo trabajador o visita externa?</p>
                     <Button 
                      variant="outline" 
                      className="rounded-xl font-black border-slate-200 text-[#116CA2] hover:bg-[#116CA2]/5 px-6"
                      onClick={() => setShowExternalForm(!showExternalForm)}
                     >
                       <UserPlus className="mr-2 size-4" />
                       REGISTRO EXTERNO
                     </Button>
                  </div>

                  {showExternalForm && (
                     <form onSubmit={handleExternalSubmit} className="space-y-4 p-6 bg-[#116CA2]/5 rounded-3xl animate-in zoom-in fade-in duration-300">
                        <div className="grid grid-cols-2 gap-4">
                           <Input 
                            placeholder="Nombre completo" 
                            className="bg-white border-none rounded-xl h-12 px-4 font-bold"
                            value={externalData.nombre}
                            onChange={(e) => setExternalData({...externalData, nombre: e.target.value})}
                            required
                           />
                           <Input 
                            placeholder="Empresa" 
                            className="bg-white border-none rounded-xl h-12 px-4 font-bold"
                            value={externalData.empresa}
                            onChange={(e) => setExternalData({...externalData, empresa: e.target.value})}
                            required
                           />
                           <Input 
                            placeholder="Patente" 
                            className="bg-white border-none rounded-xl h-12 px-4 font-bold"
                            value={externalData.patente}
                            onChange={(e) => setExternalData({...externalData, patente: e.target.value})}
                           />
                           <Input 
                            placeholder="Observación" 
                            className="bg-white border-none rounded-xl h-12 px-4 font-bold"
                            value={externalData.observacion}
                            onChange={(e) => setExternalData({...externalData, observacion: e.target.value})}
                           />
                        </div>
                        <Button className="w-full bg-[#116CA2] hover:bg-[#0d5985] rounded-xl h-12 font-black shadow-lg shadow-[#116CA2]/20" type="submit">
                           {isProcessing === 'external' ? <Loader2 className="animate-spin size-5" /> : 'REGISTRAR VISITA'}
                        </Button>
                     </form>
                  )}
               </CardContent>
            </Card>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
               <Card className="border-none shadow-lg shadow-slate-200/40 rounded-[2rem] bg-white p-8 space-y-4">
                  <div className="flex items-center gap-3">
                     <div className="size-10 rounded-xl bg-[#51872E]/10 flex items-center justify-center">
                        <Building2 className="size-5 text-[#51872E]" />
                     </div>
                     <h3 className="font-black text-[#323232] uppercase tracking-tight">Personal en Planta</h3>
                  </div>
                  <div className="flex items-end gap-2">
                     <span className="text-4xl font-black text-[#51872E]">{activeEntries.length}</span>
                     <span className="text-xs font-bold text-slate-400 mb-1.5 uppercase tracking-widest">personas</span>
                  </div>
               </Card>

               <Card className="border-none shadow-lg shadow-slate-200/40 rounded-[2rem] bg-white p-8 space-y-4">
                  <div className="flex items-center gap-3">
                     <div className="size-10 rounded-xl bg-[#FBC15F]/10 flex items-center justify-center">
                        <History className="size-5 text-[#FBC15F]" />
                     </div>
                     <h3 className="font-black text-[#323232] uppercase tracking-tight">Turno Actual</h3>
                  </div>
                  <div className="text-xs font-bold text-slate-500 uppercase tracking-widest bg-slate-50 px-3 py-1.5 rounded-lg w-fit">
                    {activePorteria === 'husamontt' ? 'Sede Husamontt' : 'Sede Tresol Antiguo'}
                  </div>
               </Card>
            </div>
          </div>

          {/* Right Column: Active Status & Logs */}
          <div className="lg:col-span-5 space-y-8">
             <Card className="border-none shadow-xl shadow-slate-200/50 rounded-[2.5rem] bg-[#323232] text-white overflow-hidden">
                <CardHeader className="p-8 pb-4">
                   <div className="flex items-center justify-between">
                     <CardTitle className="text-xl font-black uppercase tracking-tight">Personal Adentro</CardTitle>
                     <Badge className="bg-[#51872E] h-6 px-3">{activeEntries.length} ACTIVOS</Badge>
                   </div>
                   <CardDescription className="text-slate-400 font-bold">Registro de personas que no han marcado salida.</CardDescription>
                </CardHeader>
                <CardContent className="p-8 pt-0 space-y-3 max-h-[500px] overflow-y-auto scrollbar-hide">
                   {activeEntries.length === 0 ? (
                     <div className="py-10 text-center space-y-3 px-10">
                        <div className="size-16 rounded-full bg-white/5 flex items-center justify-center mx-auto mb-4">
                           <Clock className="size-8 text-slate-500" />
                        </div>
                        <p className="text-slate-400 font-bold font-sans italic">Planta vacía. No hay registros de ingreso pendientes de salida.</p>
                     </div>
                   ) : (
                     activeEntries.map(log => (
                        <div key={log.id} className="flex items-center justify-between p-4 rounded-2xl bg-white/5 border border-white/10 hover:bg-white/10 transition-all">
                           <div className="flex items-center gap-3">
                              <div className="size-10 rounded-xl bg-white/10 flex items-center justify-center">
                                 <Truck className="size-5 text-slate-300" />
                              </div>
                              <div>
                                 <p className="font-black text-sm">
                                    {log.persona ? `${log.persona.nombre} ${log.persona.apellido}` : log.nombre_manual}
                                 </p>
                                 <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">
                                    ING: {new Date(log.hora_ingreso).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })} • {log.patente || 'S/P'}
                                 </p>
                              </div>
                           </div>
                           <Button 
                            variant="destructive" 
                            className="rounded-xl font-black h-10 px-4 group/btn"
                            onClick={() => handleRegisterExit(log.id)}
                            disabled={!!isProcessing}
                           >
                              {isProcessing === `exit-${log.id}` ? <Loader2 className="animate-spin size-4" /> : 'SALIDA'}
                              {!isProcessing && <LogOut className="ml-2 size-4 transition-transform group-hover/btn:translate-x-1" />}
                           </Button>
                        </div>
                     ))
                   )}
                </CardContent>
             </Card>

             <Card className="border-none shadow-xl shadow-slate-200/50 rounded-[2.5rem] bg-white overflow-hidden">
                <CardHeader className="p-8 pb-4">
                   <CardTitle className="text-xl font-black text-[#323232] uppercase tracking-tight">Salidas Recientes</CardTitle>
                </CardHeader>
                <CardContent className="p-8 pt-0 space-y-3">
                   {recentExits.map(log => (
                      <div key={log.id} className="flex items-center justify-between p-3 rounded-xl bg-slate-50 border border-slate-100 opacity-70">
                         <div className="flex items-center gap-3">
                            <Clock className="size-4 text-slate-400" />
                            <div>
                               <p className="font-bold text-xs text-[#323232]">
