import { NextRequest, NextResponse } from 'next/server'

export async function POST(request: NextRequest) {
  try {
    const formData = await request.formData()
    const content = formData.get('content') as string
    const filename = formData.get('filename') as string

    if (!content || !filename) {
      return new NextResponse("Faltan parámetros de descarga", { status: 400 })
    }

    // Force strict headers for an attachment download
    const response = new NextResponse(content)
    response.headers.set('Content-Type', 'text/csv; charset=utf-8')
    response.headers.set('Content-Disposition', `attachment; filename="${filename}"`)
    response.headers.set('Cache-Control', 'no-store, max-age=0')

    return response
  } catch (error: any) {
    console.error('Error en API de descarga:', error)
    return new NextResponse("Error interno del servidor", { status: 500 })
  }
}

import { NextRequest, NextResponse } from 'next/server'
import fs from 'fs'
import path from 'path'

// Simple file-based lock mechanism to prevent race conditions during increments
const LOCK_FILE = path.join(process.cwd(), 'data', 'folio.lock')
const FOLIO_FILE = path.join(process.cwd(), 'data', 'last_folio.txt')
const INITIAL_FOLIO = 212192

async function acquireLock() {
  const start = Date.now()
  while (fs.existsSync(LOCK_FILE)) {
    if (Date.now() - start > 5000) throw new Error('Lock timeout')
    await new Promise(resolve => setTimeout(resolve, 50))
  }
  fs.writeFileSync(LOCK_FILE, process.pid.toString())
}

function releaseLock() {
  if (fs.existsSync(LOCK_FILE)) {
    fs.unlinkSync(LOCK_FILE)
  }
}

export async function GET() {
  try {
    const dataDir = path.join(process.cwd(), 'data')
    if (!fs.existsSync(dataDir)) {
      fs.mkdirSync(dataDir, { recursive: true })
    }

    await acquireLock()

    let currentFolio = INITIAL_FOLIO
    if (fs.existsSync(FOLIO_FILE)) {
      const content = fs.readFileSync(FOLIO_FILE, 'utf8').trim()
      currentFolio = parseInt(content, 10) + 1
    }

    // Save the new folio
    fs.writeFileSync(FOLIO_FILE, currentFolio.toString(), 'utf8')

    releaseLock()

    return NextResponse.json({ folio: currentFolio })

  } catch (error: any) {
    releaseLock()
    console.error('Folio API error:', error)
    return NextResponse.json({ error: error.message }, { status: 500 })
  }
}

import { NextRequest, NextResponse } from 'next/server'
import fs from 'fs'
import path from 'path'

export async function POST(request: NextRequest) {
  try {
    const data = await request.json()

    // Define path to the CSV file
    const dataDir = path.join(process.cwd(), 'data')
    const filePath = path.join(dataDir, 'registro_servicios.csv')

    // Ensure directory exists
    if (!fs.existsSync(dataDir)) {
      fs.mkdirSync(dataDir, { recursive: true })
    }

    // CSV Headers
    const headers = [
      'Folio',
      'Fecha',
      'Empresa',
      'Planta',
      'Patente',
      'Chofer',
      'Categoria',
      'Cantidad',
      'Unidad',
      'Destino',
      'Contenedor',
      'Salida',
      'Observaciones'
    ]

    const exists = fs.existsSync(filePath)

    // Clean and format values for CSV (using semicolon for LatAm Excel)
    const safe = (v: any) => String(v == null ? '' : v).replace(/;/g, ',').replace(/\n/g, ' ').trim()

    const row = [
      safe(data.folio),
      safe(new Date().toLocaleDateString('es-CL')),
      safe(data.empresa),
      safe(data.planta_lugar),
      safe(data.patente),
      safe(data.nombre_conductor),
      safe(data.categoria),
      safe(data.valor),
      safe(data.unidad),
      safe(data.destino_tipo),
      safe(data.contenedor_tipo),
      safe(data.salida_pm),
      safe(data.observaciones)
    ].join(';')

    let content = ''
    if (!exists) {
      // Add UTF-8 BOM for Excel compatibility + Headers
      content = '\uFEFF' + headers.join(';') + '\r\n'
    }
    content += row + '\r\n'

    // Append to file
    fs.appendFileSync(filePath, content, 'utf8')

    return NextResponse.json({ success: true })

  } catch (error: any) {
    console.error('Logger API error:', error)
    return NextResponse.json({ error: error.message }, { status: 500 })
  }
}

export async function GET() {
  try {
    const dataFile = path.join(process.cwd(), 'data', 'registro_servicios.csv')

    if (!fs.existsSync(dataFile)) {
      return NextResponse.json({ comprobantes: [] })
    }

    const content = fs.readFileSync(dataFile, 'utf8')
    // Remove BOM if present
    const cleanContent = content.startsWith('\uFEFF') ? content.slice(1) : content

    const lines = cleanContent.split('\r\n').filter(l => l.trim() !== '')
    if (lines.length <= 1) return NextResponse.json({ comprobantes: [] })

    const headers = lines[0].split(';')
    const comprobantes = lines.slice(1).map((line, index) => {
      const values = line.split(';')
      const entry: any = { id: `csv-${index}` }
      headers.forEach((h, i) => {
        // Map headers to internal names if needed, or just use lowercase
        const key = h.toLowerCase().replace(/ /g, '_')
        entry[key] = values[i]
      })

      // Normalize specific fields for the UI
      return {
        ...entry,
        // UI expects 'folio', 'empresa', 'planta_lugar', 'fecha', 'patente', 'nombre_conductor'
        folio: entry.folio,
        fecha: entry.fecha,
        empresa: entry.empresa,
        planta_lugar: entry.planta,
        patente: entry.patente,
        nombre_conductor: entry.chofer,
        salida_pm: entry.salida,
        observaciones: entry.observaciones,
        categoria: entry.categoria,
        cantidad: entry.cantidad,
        unidad: entry.unidad,
        destino_tipo: entry.destino,
        contenedor_tipo: entry.contenedor
      }
    })

    return NextResponse.json({ comprobantes })

  } catch (error: any) {
    console.error('Logger API GET error:', error)
    return NextResponse.json({ error: error.message }, { status: 500 })
  }
}

import { NextRequest, NextResponse } from 'next/server'
import { supabaseAdmin as supabase } from '@/lib/supabase-admin'

export async function POST(request: NextRequest) {
  try {
    const { table, data, method, match } = await request.json()

    let query = supabase.from(table)
    let result: any

    if (method === 'insert') {
      // Silently satisfy not-null constraints for specific tables if missing
      if (table === 'servicios_asignados') {
        if (Array.isArray(data)) {
          data.forEach(item => {
            if (!item.tipo_servicio) item.tipo_servicio = 'RETIRO';
          });
        }
      }
      result = await query.insert(data)
    } else if (method === 'update') {
      result = await query.update(data).match(match)
    } else if (method === 'select') {
      let q = query.select(data || '*')
      if (match) {
        Object.entries(match).forEach(([key, value]) => {
          q = q.eq(key, value)
        })
      }

      // Simply execute the query. Sorting is removed for performance.
      result = await q
    } else if (method === 'delete') {
      let q = query.delete()
      if (match && Object.keys(match).length > 0) {
        Object.entries(match).forEach(([key, value]) => {
          q = q.eq(key, value)
        })
      } else {
        // Supabase requires a filter for deletes. Use a universal neq for cleanup.
        q = q.neq('id', '00000000-0000-0000-0000-000000000000')
      }
      result = await q
    } else {
      throw new Error("Método no soportado")
    }

    console.log(`Proxy success [${method}] on [${table}]:`, result.data?.length || '1 item')

    if (result.error) throw result.error

    return NextResponse.json({ success: true, data: result.data })
  } catch (error: any) {
    console.error('Proxy API error:', error)
    return NextResponse.json({ error: error.message }, { status: 500 })
  }
}

